import { useCallback, useEffect, useState } from 'react';

/**
 * Public homepage evidence strip (idea-run-6 / F.004). Loads
 * /live-evidence.json — generated by scripts/build-live-evidence-manifest.mjs
 * in the HoloScript repo (fleet ledger + .base.json anchors + git).
 *
 * Note: GET /api/holomesh/fleet/status?team=… is team+auth-gated; the marketing
 * root cannot call it from the browser without a server proxy. The manifest
 * already encodes the same public-verifiable fleet tile inputs.
 */
const DEFAULT_MANIFEST = '/live-evidence.json';
const POLL_MS = 30_000;

type FleetTile = {
  agentsLast24h: number;
  spendUsd24h: number;
  commitsLast24h: number;
};

type AnchorTile = {
  fileName?: string;
  fileSha256Short?: string;
  blockNumber?: number;
  txHash?: string;
  basescanUrl?: string;
  relativeTime?: string;
  note?: string;
};

type CommitTile = {
  repo?: string;
  hash?: string;
  hashShort?: string;
  subject?: string;
  relativeTime?: string;
  githubUrl?: string;
  note?: string;
};

type LiveEvidenceDoc = {
  generatedAt: string;
  tiles: {
    fleet: FleetTile & { note?: string | null };
    anchor: AnchorTile;
    commit: CommitTile;
  };
};

function fmtUsd(n: number) {
  if (typeof n !== 'number' || Number.isNaN(n)) return '$0';
  if (n < 0.01) return '<$0.01';
  return `$${n.toFixed(2)}`;
}

export function LiveEvidenceStrip() {
  const [data, setData] = useState<LiveEvidenceDoc | null>(null);
  const [loadError, setLoadError] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  const manifestUrl = DEFAULT_MANIFEST;

  const load = useCallback(async () => {
    try {
      const res = await fetch(manifestUrl, { cache: 'no-cache' });
      if (!res.ok) {
        throw new Error(`HTTP ${res.status}`);
      }
      const json = (await res.json()) as LiveEvidenceDoc;
      setData(json);
      setLoadError(null);
    } catch (e) {
      setLoadError((e as Error).message || String(e));
    } finally {
      setLoading(false);
    }
  }, [manifestUrl]);

  useEffect(() => {
    void load();
    const id = window.setInterval(() => {
      void load();
    }, POLL_MS);
    return () => window.clearInterval(id);
  }, [load]);

  const ageMs = data?.generatedAt
    ? Date.now() - new Date(data.generatedAt).getTime()
    : 0;
  const ageHours = ageMs / 3_600_000;
  const isStale = ageMs > 0 && ageHours > 12;
  const ageLabel =
    !data?.generatedAt || !Number.isFinite(ageMs)
      ? ''
      : ageHours < 1
        ? `${Math.max(1, Math.round(ageMs / 60_000))} min ago`
        : ageHours < 24
          ? `${Math.round(ageHours)} h ago`
          : `${Math.floor(ageHours / 24)} d ago`;

  const fleet = data?.tiles?.fleet;
  const anchor = data?.tiles?.anchor;
  const commit = data?.tiles?.commit;

  if (loading) {
    return (
      <div className="w-full border-b border-cyan-500/15 bg-black/40 text-[11px] text-gray-500 py-2 px-6 text-center font-mono">
        Loading live evidence…
      </div>
    );
  }

  return (
    <section className="w-full bg-black/35 border-b border-cyan-500/20 text-[#e0e6ee] py-3" aria-label="Live evidence">
      {loadError ? (
        <div className="max-w-6xl mx-auto px-4 text-amber-400/90 text-xs font-mono text-center">
          live-evidence manifest unreachable: {loadError}
        </div>
      ) : (
        <>
          <div className="max-w-6xl mx-auto px-4 grid grid-cols-1 md:grid-cols-3 gap-4 md:gap-6 text-sm">
            <div className="min-w-0">
              <div className="text-[10px] uppercase tracking-widest text-gray-500 font-semibold mb-1">Fleet, last 24 h</div>
              {fleet ? (
                <div className="flex flex-wrap gap-x-1.5 gap-y-0.5 items-baseline text-xs">
                  <span className="font-semibold text-white">{fleet.agentsLast24h}</span>
                  <span className="text-gray-400">{fleet.agentsLast24h === 1 ? 'agent' : 'agents'}</span>
                  <span className="text-gray-600">·</span>
                  <span className="font-semibold text-white">{fmtUsd(fleet.spendUsd24h)}</span>
                  <span className="text-gray-400">spent</span>
                  <span className="text-gray-600">·</span>
                  <span className="font-semibold text-white">{fleet.commitsLast24h}</span>
                  <span className="text-gray-400">{fleet.commitsLast24h === 1 ? 'commit' : 'commits'}</span>
                </div>
              ) : (
                <div className="text-xs text-gray-500 italic">no fleet data</div>
              )}
            </div>

            <div className="min-w-0">
              <div className="text-[10px] uppercase tracking-widest text-gray-500 font-semibold mb-1">Last paper anchored on Base</div>
              {anchor?.txHash && anchor.basescanUrl ? (
                <div>
                  <a
                    href={anchor.basescanUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-cyan-200/90 border-b border-dotted border-cyan-500/40 hover:border-cyan-400 break-all text-xs font-mono"
                  >
                    {anchor.fileName}
                    <span className="text-gray-500"> · </span>sha {anchor.fileSha256Short}…
                    {anchor.blockNumber != null && (
                      <>
                        <span className="text-gray-500"> · </span>block {anchor.blockNumber}
                      </>
                    )}
                  </a>
                  {anchor.relativeTime && (
                    <span className="ml-1.5 text-gray-500 text-xs">{anchor.relativeTime}</span>
                  )}
                </div>
              ) : (
                <div className="text-xs text-gray-500 italic">no anchor receipts found</div>
              )}
            </div>

            <div className="min-w-0">
              <div className="text-[10px] uppercase tracking-widest text-gray-500 font-semibold mb-1">Last commit</div>
              {commit?.hash && commit.githubUrl ? (
                <div>
                  <a
                    href={commit.githubUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-cyan-200/90 border-b border-dotted border-cyan-500/40 hover:border-cyan-400 text-xs font-mono"
                  >
                    {commit.repo} {commit.hashShort}
                  </a>
                  {commit.relativeTime && <span className="ml-1.5 text-gray-500 text-xs">{commit.relativeTime}</span>}
                  {commit.subject && (
                    <div className="text-gray-500 text-xs mt-0.5 truncate" title={commit.subject}>
                      {commit.subject}
                    </div>
                  )}
                </div>
              ) : (
                <div className="text-xs text-gray-500 italic">no commits found</div>
              )}
            </div>
          </div>
          <div className="max-w-6xl mx-auto px-4 mt-2 pt-2 border-t border-white/[0.06] flex flex-col sm:flex-row sm:justify-between sm:items-center gap-1 text-[10px] text-gray-500">
            <span className="font-mono">Refreshed {ageLabel}</span>
            {isStale && <span className="text-amber-400/90">Data older than 12 h; manifest may refresh on cron (see repo script).</span>}
            <span>
              <a className="hover:text-cyan-300" href="https://holoscript.net/docs/provenance">
                /provenance
              </a>
              <span className="mx-1.5">·</span>
              <a className="hover:text-cyan-300" href="https://holoscript.net/docs/papers/status">
                /papers/status
              </a>
            </span>
          </div>
        </>
      )}
    </section>
  );
}

export default LiveEvidenceStrip;
